struct Item2 { id: u64, version: u64 }
impl PartialEq for Item2 { fn eq(&self, o: &Self) -> bool { self.id == o.id } }
impl Eq for Item2 {}
impl std::hash::Hash for Item2 {
    fn hash<H: std::hash::Hasher>(&self, state: &mut H) { self.id.hash(state); }
}
// Now: a == b ⟺ hash(a) == hash(b). Contract preserved.

