// size_of::<Bad>() == 24

good_pattern:
#[repr(C)]
struct Better {
    b: u64,  // 8 bytes (largest first)
    a: u8,   // 1 byte
    c: u8,   // 1 byte + 6 trailing padding
}
// size_of::<Better>() == 16

// Or: drop #[repr(C)] entirely and let the compiler reorder — `repr(Rust)` does
// the equivalent reorder for you and may pick an even tighter layout.
struct AutoLayout { a: u8, b: u64, c: u8 }

anti_pattern:
use std::sync::atomic::{AtomicU64, Ordering};
let counter = AtomicU64::new(0);
// Stat counter that is never read with synchronization meaning — SeqCst is overkill.
counter.fetch_add(1, Ordering::SeqCst);

good_pattern:
use std::sync::atomic::{AtomicBool, AtomicU64, Ordering};
// Stat counter: no inter-thread ordering needed.
let counter = AtomicU64::new(0);
counter.fetch_add(1, Ordering::Relaxed);

// One-shot signal: writer publishes data, then sets the flag with Release;
// reader checks the flag with Acquire and only then reads the data.
let ready = AtomicBool::new(false);
// writer side (real code wraps shared data in UnsafeCell or other atomics)
// ...write data fields...
ready.store(true, Ordering::Release);
// reader side
while !ready.load(Ordering::Acquire) { std::hint::spin_loop(); }
// ...read data fields, guaranteed visible...

