struct Config {
    timeout: Box<u32>,   // u32 is Copy and 4 bytes — Box adds alloc + pointer indirection for nothing
    name: Box<String>,   // String already owns its bytes on the heap; Box<String> double-indirects
}

good_pattern:
struct Config {
    timeout: u32,   // stack, direct access
    name: String,   // already heap-allocated; one indirection is enough
}
// Legitimate Box uses:
struct Plugin { handler: Box<dyn EventHandler> }            // trait object
struct LinkedList<T> { head: Option<Box<Node<T>>> }         // recursive type
struct Frame { huge_buffer: Box<[u8; 4 * 1024 * 1024]> }    // genuinely large; avoid stack overflow

anti_pattern:
fn first_unchecked<T>(v: &[T]) -> &T {
    // No SAFETY comment — reviewer cannot tell whether the caller checked emptiness.
    unsafe { v.get_unchecked(0) }
}

good_pattern:
fn first_unchecked<T>(v: &[T]) -> &T {
    debug_assert!(!v.is_empty());
    // SAFETY: caller-visible debug_assert and the &[T] type guarantee no other
    // mutable borrow exists; index 0 is in bounds because v is non-empty by
    // the function's documented precondition.
    unsafe { v.get_unchecked(0) }
}

anti_pattern:
// `unsafe` with no documentation — a caller has no way to know what to verify.
pub unsafe fn copy_n<T>(src: *const T, dst: *mut T, n: usize) {
    std::ptr::copy_nonoverlapping(src, dst, n);
}

good_pattern:
/// Copies `n` values of `T` from `src` to `dst`.
///
/// # Safety
///
/// - `src` must be valid for reads of `n * size_of::<T>()` bytes.
/// - `dst` must be valid for writes of `n * size_of::<T>()` bytes.
/// - The two regions must not overlap.
/// - Both pointers must be properly aligned for `T`.
pub unsafe fn copy_n<T>(src: *const T, dst: *mut T, n: usize) {
    // SAFETY: the four preconditions in this function's `# Safety` section
    // are exactly those of `ptr::copy_nonoverlapping` (read-validity,
    // write-validity, non-overlap, alignment); we forward them unchanged
    // from the caller, who has signed our contract.
    unsafe { std::ptr::copy_nonoverlapping(src, dst, n) }
}

anti_pattern:
// One large unsafe block hides which line is the actually-unsafe one.
unsafe fn split_at_mut_unchecked<T>(s: &mut [T], mid: usize) -> (&mut [T], &mut [T]) {
    unsafe {
        let len = s.len();
        let ptr = s.as_mut_ptr();
        // bounds reasoning, pointer arithmetic, and the actual unsafe ops all
        // live inside the same block — reviewer must squint at every line.
        (
            std::slice::from_raw_parts_mut(ptr, mid),
            std::slice::from_raw_parts_mut(ptr.add(mid), len - mid),
        )
    }
}

good_pattern:
/// # Safety
/// `mid <= s.len()` must hold.
unsafe fn split_at_mut_unchecked<T>(s: &mut [T], mid: usize) -> (&mut [T], &mut [T]) {
    let len = s.len();
    let ptr = s.as_mut_ptr();
    // SAFETY: caller guarantees mid <= len. ptr came from `&mut [T]` so it is
    // non-null, properly aligned for T, points to len consecutive initialized
    // values, and the allocation fits within isize::MAX. The two halves are
    // disjoint by construction so no aliasing &mut is created and no other
    // pointer reads or writes this memory for the borrow's lifetime.
    let left = unsafe { std::slice::from_raw_parts_mut(ptr, mid) };
    // SAFETY: same caller guarantee and same alignment/initialization/size
    // properties carried over from the original `&mut [T]`. `ptr.add(mid)` is
    // in-bounds because mid <= len, and the right half is disjoint from the
    // left because their byte ranges do not overlap.
    let right = unsafe { std::slice::from_raw_parts_mut(ptr.add(mid), len - mid) };
    (left, right)
}

