use std::mem::MaybeUninit;
struct Pair { a: u32, b: String }
let mut p = MaybeUninit::<Pair>::uninit();
// UB: &mut Pair is invalid because Pair is not yet initialized; the mere
// existence of this reference is undefined behavior, even before reading.
let pref: &mut Pair = unsafe { &mut *p.as_mut_ptr() };
pref.a = 1;
pref.b = String::from("hi");

good_pattern:
use std::mem::MaybeUninit;
use std::ptr::addr_of_mut;
struct Pair { a: u32, b: String }
let mut p = MaybeUninit::<Pair>::uninit();
let ptr = p.as_mut_ptr();
// SAFETY: addr_of_mut! takes a place expression and yields a raw pointer
// without materializing a &mut to the partially-initialized Pair.
unsafe {
    addr_of_mut!((*ptr).a).write(1);
    addr_of_mut!((*ptr).b).write(String::from("hi"));
}
// SAFETY: every field of Pair has been initialized above.
let pair: Pair = unsafe { p.assume_init() };

anti_pattern:
// The cast itself is fine — pointer-type punning is well-defined. The UB is
// the *write through* `*mut i32` to memory that is borrowed as `&i32`: the
// shared reference guarantees the value does not change while it is live, and
// `value` is not inside an `UnsafeCell`. The borrow checker accepts the code,
// but the abstract machine does not.
fn bad_set(value: &i32, new: i32) {
    let ptr = value as *const i32 as *mut i32;
    unsafe { *ptr = new; }
}

good_pattern:
use std::cell::Cell;
// Sound: Cell wraps an UnsafeCell internally and exposes a safe API.
fn good_set(slot: &Cell<i32>, new: i32) {
    slot.set(new);
}
// Or, when the existing wrappers don't fit, build on UnsafeCell directly:
use std::cell::UnsafeCell;
struct MyCell<T> { inner: UnsafeCell<T> }
impl<T> MyCell<T> {
    /// # Safety
    /// Caller must ensure no other reference (shared or unique) into `inner`
    /// is live when this method runs. Validity, alignment, and initialization
    /// are upheld by `MyCell`'s own invariants: `UnsafeCell::get` returns a
    /// valid, properly-aligned `*mut T` that points to an initialized `T` for
    /// as long as `&self` is live.
    unsafe fn replace(&self, new: T) -> T {
        // SAFETY: ptr::replace requires (1) valid for reads and writes, (2)
        // properly aligned, (3) points to an initialized T. (1)-(3) follow
        // from MyCell's structural invariants. The fourth requirement — no
        // other live reference into `inner` — is the caller's obligation.
        unsafe { std::ptr::replace(self.inner.get(), new) }
    }
}

anti_pattern:
let mut x = 1u32;
let ptr: *mut u32 = &mut x;
// `shared` is a live &u32 borrow rooted at `ptr`.
let shared: &u32 = unsafe { &*ptr };
// UB under Stacked Borrows: materializing &mut u32 from `ptr` invalidates
// `shared` at the moment the &mut is created, before any read happens.
// The subsequent read through `shared` is undefined behavior.
let exclusive: &mut u32 = unsafe { &mut *ptr };
*exclusive = 2;
let _ = *shared;

good_pattern:
let mut x = 1u32;
let ptr: *mut u32 = &mut x;
// Stay in raw pointers while both reads/writes are needed; raw pointers do
// not impose aliasing, so `read`/`write` through `ptr` is sound.
unsafe {
    let cur = ptr.read();
    ptr.write(cur + 1);
}
// SAFETY: ptr is valid for the lifetime of x, and no other reference to x
// is live at this point (the raw-pointer ops above produced no borrow).
let final_ref: &u32 = unsafe { &*ptr };
assert_eq!(*final_ref, 2);

anti_pattern:
// Three problems: panic across boundary is UB, &mut MyType is exposed,
// and the function is generic (won't compile, but the intent is wrong).
#[unsafe(no_mangle)]
pub extern "C" fn process<T>(value: &mut T) -> i32 {
    panic!("unimplemented"); // UB if the caller is C
}

good_pattern:
use std::panic::catch_unwind;

#[repr(C)]
pub struct MyType { field: u32 }

/// Processes a MyType value.
///
/// # Safety
/// `value` must be a non-null pointer to a valid MyType for the duration
/// of the call. Caller retains ownership; this function does not free.
///
/// Returns 0 on success, -1 on caller error, -2 on internal panic.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn my_process(value: *mut MyType) -> i32 {
    if value.is_null() { return -1; }
    catch_unwind(|| {
        // SAFETY: caller-documented non-null and validity precondition.
        let v = unsafe { &mut *value };
        v.field = v.field.saturating_add(1);
        0
    })
    .unwrap_or(-2)
}

