// repr(Rust) — the field order can change between compiler versions,
// breaking C callers that assumed declaration order.
pub struct Header {
    pub kind: u8,
    pub length: u32,
}
// Vec<u8> has no stable layout — `extern "C" fn read(out: Vec<u8>)` is UB.
extern "C" {
    fn read(out: Vec<u8>) -> i32;
}

good_pattern:
use std::ffi::{c_int, c_uchar};
use std::ptr::NonNull;

#[repr(C)]
pub struct Header {
    pub kind: c_uchar,
    pub length: c_int,
    // Niche-optimized nullable pointer: same size as *mut Body, distinguishes
    // null at the type level so callers must pattern-match.
    pub body: Option<NonNull<Body>>,
}

#[repr(C)]
pub struct Body {
    pub bytes: *mut c_uchar,
    pub len: usize,
}

#[repr(u8)]
pub enum Status { Ok = 0, Err = 1 }

anti_pattern:
use std::ffi::c_char;
// Returns a C string with no documented ownership convention. Caller has
// no idea whether they should call free, a Rust-provided destructor, or
// nothing at all (which leaks).
#[unsafe(no_mangle)]
pub extern "C" fn build_message() -> *const c_char {
    let s = std::ffi::CString::new("hello").unwrap();
    s.as_ptr() // dangling: CString drops at end of scope!
}

good_pattern:
use std::ffi::{CStr, CString, c_char};

/// Borrows a C string for inspection. The caller retains ownership.
///
/// # Safety
/// `s` must be a non-null, NUL-terminated C string valid for the call.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn message_len(s: *const c_char) -> usize {
    if s.is_null() { return 0; }
    // SAFETY: caller's documented non-null + NUL-terminated precondition.
    unsafe { CStr::from_ptr(s) }.to_bytes().len()
}

/// Builds a Rust-owned C string and transfers ownership to C.
/// C must release the value with `free_message`, not `free`.
#[unsafe(no_mangle)]
pub extern "C" fn build_message() -> *mut c_char {
    CString::new("hello").map(CString::into_raw).unwrap_or(std::ptr::null_mut())
}

/// Reclaims and frees a string previously returned by `build_message`.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn free_message(s: *mut c_char) {
    if s.is_null() { return; }
    // SAFETY: caller passes a pointer obtained from CString::into_raw
    // and never freed by any other path.
    drop(unsafe { CString::from_raw(s) });
}
